  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  4→
  5→const ProjectContext = createContext(null);
  6→const HISTORY_LIMIT = 100;
  7→
  8→function snapshotProject(project) {
  9→  return JSON.stringify(project);
 10→}
 11→
 12→function getFloor(state, floorId) {
 13→  return state.project.floors.find(f => f.id === floorId);
 14→}
 15→
 16→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 17→  const nextSnapshot = snapshotProject(nextProject);
 18→  const history = recordHistory
 19→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 20→    : state.history;
 21→
 22→  return {
 23→    ...state,
 24→    history,
 25→    future: recordHistory ? [] : state.future,
 26→    project: nextProject,
 27→    isDirty: nextSnapshot !== state.savedSnapshot,
 28→  };
 29→}
 30→
 31→function updateFloor(state, floorId, updater, recordHistory = true) {
 32→  return applyProjectUpdate(state, {
 33→    ...state.project,
 34→    updatedAt: new Date().toISOString(),
 35→    floors: state.project.floors.map(f =>
 36→      f.id === floorId ? updater(f) : f
 37→    ),
 38→  }, recordHistory);
 39→}
 40→
 41→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 42→  const nextWall = { ...existingWall, ...wallUpdate };
 43→
 44→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 45→    nextWall.startAttachment = null;
 46→  }
 47→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 48→    nextWall.endAttachment = null;
 49→  }
 50→
 51→  return syncWallAttachmentPoints(nextWall, columns);
 52→}
 53→
 54→function projectReducer(state, action) {
 55→  switch (action.type) {
 56→    case 'PROJECT_NEW':
 57→      return {
 58→        project: action.project,
 59→        isDirty: false,
 60→        lastSavedAt: null,
 61→        savedSnapshot: snapshotProject(action.project),
 62→        history: [],
 63→        future: [],
 64→      };
 65→
 66→    case 'PROJECT_LOAD':
 67→      return {
 68→        project: action.project,
 69→        isDirty: false,
 70→        lastSavedAt: action.savedAt || null,
 71→        savedSnapshot: snapshotProject(action.project),
 72→        history: [],
 73→        future: [],
 74→      };
 75→
 76→    case 'PROJECT_SET_NAME':
 77→      return applyProjectUpdate(state, {
 78→        ...state.project,
 79→        name: action.name,
 80→        updatedAt: new Date().toISOString(),
 81→      });
 82→
 83→    case 'SHEET_ADD':
 84→      return applyProjectUpdate(state, {
 85→        ...state.project,
 86→        updatedAt: new Date().toISOString(),
 87→        sheets: [...(state.project.sheets || []), action.sheet],
 88→      });
 89→
 90→    case 'SHEET_UPDATE':
 91→      return applyProjectUpdate(state, {
 92→        ...state.project,
 93→        updatedAt: new Date().toISOString(),
 94→        sheets: (state.project.sheets || []).map((sheet) => (
 95→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
 96→        )),
 97→      });
 98→
 99→    case 'SHEET_DELETE':
100→      return applyProjectUpdate(state, {
101→        ...state.project,
102→        updatedAt: new Date().toISOString(),
103→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
104→      });
105→
106→    case 'SHEET_VIEWPORT_ADD':
107→      return applyProjectUpdate(state, {
108→        ...state.project,
109→        updatedAt: new Date().toISOString(),
110→        sheets: (state.project.sheets || []).map((sheet) => (
111→          sheet.id === action.sheetId
112→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
113→            : sheet
114→        )),
115→      });
116→
117→    case 'SHEET_VIEWPORT_UPDATE':
118→      return applyProjectUpdate(state, {
119→        ...state.project,
120→        updatedAt: new Date().toISOString(),
121→        sheets: (state.project.sheets || []).map((sheet) => (
122→          sheet.id === action.sheetId
123→            ? {
124→                ...sheet,
125→                viewports: (sheet.viewports || []).map((viewport) => (
126→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
127→                )),
128→              }
129→            : sheet
130→        )),
131→      });
132→
133→    case 'SHEET_VIEWPORT_DELETE':
134→      return applyProjectUpdate(state, {
135→        ...state.project,
136→        updatedAt: new Date().toISOString(),
137→        sheets: (state.project.sheets || []).map((sheet) => (
138→          sheet.id === action.sheetId
139→            ? {
140→                ...sheet,
141→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
142→              }
143→            : sheet
144→        )),
145→      });
146→
147→    case 'WALL_ADD':
148→      return updateFloor(state, action.floorId, f => ({
149→        ...f,
150→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
151→      }));
152→
153→    case 'WALL_UPDATE':
154→      return updateFloor(state, action.floorId, f => ({
155→        ...f,
156→        walls: f.walls.map(w => (
157→          w.id === action.wall.id
158→            ? mergeWallUpdate(w, action.wall, f.columns || [])
159→            : w
160→        )),
161→      }));
162→
163→    case 'WALL_DELETE': {
164→      const wallId = action.wallId;
165→      return updateFloor(state, action.floorId, f => ({
166→        ...f,
167→        walls: f.walls.filter(w => w.id !== wallId),
168→        doors: f.doors.filter(d => d.wallId !== wallId),
169→        windows: f.windows.filter(w => w.wallId !== wallId),
170→      }));
171→    }
172→
173→    case 'DOOR_ADD':
174→      return updateFloor(state, action.floorId, f => ({
175→        ...f,
176→        doors: [...f.doors, action.door],
177→      }));
178→
179→    case 'DOOR_UPDATE':
180→      return updateFloor(state, action.floorId, f => ({
181→        ...f,
182→        doors: f.doors.map(d => d.id === action.door.id ? { ...d, ...action.door } : d),
183→      }));
184→
185→    case 'DOOR_DELETE':
186→      return updateFloor(state, action.floorId, f => ({
187→        ...f,
188→        doors: f.doors.filter(d => d.id !== action.doorId),
189→      }));
190→
191→    case 'WINDOW_ADD':
192→      return updateFloor(state, action.floorId, f => ({
193→        ...f,
194→        windows: [...f.windows, action.window],
195→      }));
196→
197→    case 'WINDOW_UPDATE':
198→      return updateFloor(state, action.floorId, f => ({
199→        ...f,
200→        windows: f.windows.map(w => w.id === action.window.id ? { ...w, ...action.window } : w),
201→      }));
202→
203→    case 'WINDOW_DELETE':
204→      return updateFloor(state, action.floorId, f => ({
205→        ...f,
206→        windows: f.windows.filter(w => w.id !== action.windowId),
207→      }));
208→
209→    case 'BEAM_ADD':
210→      return updateFloor(state, action.floorId, f => ({
211→        ...f,
212→        beams: [...(f.beams || []), action.beam],
213→      }));
214→
215→    case 'BEAM_UPDATE':
216→      return updateFloor(state, action.floorId, f => ({
217→        ...f,
218→        beams: (f.beams || []).map(beam => (
219→          beam.id === action.beam.id ? { ...beam, ...action.beam } : beam
220→        )),
221→      }));
222→
223→    case 'BEAM_DELETE':
224→      return updateFloor(state, action.floorId, f => ({
225→        ...f,
226→        beams: (f.beams || []).filter(beam => beam.id !== action.beamId),
227→      }));
228→
229→    case 'STAIR_ADD':
230→      return updateFloor(state, action.floorId, f => ({
231→        ...f,
232→        stairs: [...(f.stairs || []), action.stair],
233→      }));
234→
235→    case 'STAIR_UPDATE':
236→      return updateFloor(state, action.floorId, f => ({
237→        ...f,
238→        stairs: (f.stairs || []).map(stair => (
239→          stair.id === action.stair.id ? { ...stair, ...action.stair } : stair
240→        )),
241→      }));
242→
243→    case 'STAIR_DELETE':
244→      return updateFloor(state, action.floorId, f => ({
245→        ...f,
246→        stairs: (f.stairs || []).filter(stair => stair.id !== action.stairId),
247→      }));
248→
249→    case 'ANNOTATION_ADD':
250→      return updateFloor(state, action.floorId, f => ({
251→        ...f,
252→        annotations: [...(f.annotations || []), action.annotation],
253→      }));
254→
255→    case 'ANNOTATION_UPDATE':
256→      return updateFloor(state, action.floorId, f => ({
257→        ...f,
258→        annotations: (f.annotations || []).map((annotation) => (
259→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
260→        )),
261→      }));
262→
263→    case 'ANNOTATION_DELETE':
264→      return updateFloor(state, action.floorId, f => ({
265→        ...f,
266→        annotations: (f.annotations || []).filter((annotation) => annotation.id !== action.annotationId),
267→      }));
268→
269→    case 'ANNOTATION_SETTINGS_UPDATE':
270→      return updateFloor(state, action.floorId, f => ({
271→        ...f,
272→        annotationSettings: {
273→          ...(f.annotationSettings || {}),
274→          ...action.settings,
275→        },
276→      }));
277→
278→    case 'SLAB_ADD':
279→      return updateFloor(state, action.floorId, f => ({
280→        ...f,
281→        slabs: [...(f.slabs || []), action.slab],
282→      }));
283→
284→    case 'SLAB_UPDATE':
285→      return updateFloor(state, action.floorId, f => ({
286→        ...f,
287→        slabs: (f.slabs || []).map(s =>
288→          s.id === action.slab.id ? { ...s, ...action.slab } : s
289→        ),
290→      }));
291→
292→    case 'SLAB_DELETE':
293→      return updateFloor(state, action.floorId, f => ({
294→        ...f,
295→        slabs: (f.slabs || []).filter(s => s.id !== action.slabId),
296→      }));
297→
298→    case 'SECTION_ADD':
299→      return updateFloor(state, action.floorId, f => ({
300→        ...f,
301→        sectionCuts: [...(f.sectionCuts || []), action.sectionCut],
302→      }));
303→
304→    case 'SECTION_UPDATE':
305→      return updateFloor(state, action.floorId, f => ({
306→        ...f,
307→        sectionCuts: (f.sectionCuts || []).map(s =>
308→          s.id === action.sectionCut.id ? { ...s, ...action.sectionCut } : s
309→        ),
310→      }));
311→
312→    case 'SECTION_DELETE':
313→      return updateFloor(state, action.floorId, f => ({
314→        ...f,
315→        sectionCuts: (f.sectionCuts || []).filter(s => s.id !== action.sectionId),
316→      }));
317→
318→    case 'ROOM_ADD':
319→      return updateFloor(state, action.floorId, f => ({
320→        ...f,
321→        rooms: [...f.rooms, action.room],
322→      }));
323→
324→    case 'ROOM_UPDATE':
325→      return updateFloor(state, action.floorId, f => ({
326→        ...f,
327→        rooms: f.rooms.map(r => r.id === action.room.id ? { ...r, ...action.room } : r),
328→      }));
329→
330→    case 'ROOM_DELETE':
331→      return updateFloor(state, action.floorId, f => ({
332→        ...f,
333→        rooms: f.rooms.filter(r => r.id !== action.roomId),
334→      }));
335→
336→    case 'ROOMS_SET':
337→      return updateFloor(state, action.floorId, f => ({
338→        ...f,
339→        rooms: action.rooms,
340→      }));
341→
342→    case 'FLOOR_REPLACE':
343→      return updateFloor(state, action.floorId, () => ({
344→        ...action.floor,
345→      }));
346→
347→    case 'COLUMN_ADD':
348→      return updateFloor(state, action.floorId, f => ({
349→        ...f, columns: [...(f.columns || []), action.column],
350→      }));
351→    case 'COLUMN_DUPLICATE':
352→      return updateFloor(state, action.floorId, f => ({
353→        ...f,
354→        columns: [...(f.columns || []), action.column],
355→      }));
356→    case 'COLUMN_UPDATE':
357→      return updateFloor(state, action.floorId, f => {
358→        const nextColumns = (f.columns || []).map(c => (
359→          c.id === action.column.id ? { ...c, ...action.column } : c
360→        ));
361→        return {
362→          ...f,
363→          columns: nextColumns,
364→          walls: f.walls.map(w => syncWallAttachmentPoints(w, nextColumns)),
365→        };
366→      });
367→    case 'COLUMN_DELETE':
368→      return updateFloor(state, action.floorId, f => ({
369→        ...f,
370→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
371→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
372→        beams: (f.beams || []).filter(beam => (
373→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
374→        )),
375→      }));
376→
377→    case 'MARK_SAVED':
378→      return {
379→        ...state,
380→        isDirty: false,
381→        lastSavedAt: new Date().toISOString(),
382→        savedSnapshot: snapshotProject(state.project),
383→      };
384→
385→    case 'UNDO': {
386→      if (state.history.length === 0) return state;
387→      const previousProject = state.history[state.history.length - 1];
388→      return {
389→        ...state,
390→        project: previousProject,
391→        history: state.history.slice(0, -1),
392→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
393→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
394→      };
395→    }
396→
397→    case 'REDO': {
398→      if (state.future.length === 0) return state;
399→      const nextProject = state.future[0];
400→      return {
401→        ...state,
402→        project: nextProject,
403→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
404→        future: state.future.slice(1),
405→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
406→      };
407→    }
408→
409→    default:
410→      return state;
411→  }
412→}
413→
414→const initialProject = createProject();
415→
416→const initialState = {
417→  project: initialProject,
418→  isDirty: false,
419→  lastSavedAt: null,
420→  savedSnapshot: snapshotProject(initialProject),
421→  history: [],
422→  future: [],
423→};
424→
425→export function ProjectProvider({ children }) {
426→  const [state, dispatch] = useReducer(projectReducer, initialState);
427→  return (
428→    <ProjectContext.Provider value={{ state, dispatch }}>
429→      {children}
430→    </ProjectContext.Provider>
431→  );
432→}
433→
434→export function useProject() {
435→  const ctx = useContext(ProjectContext);
436→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
437→  const { state, dispatch } = ctx;
438→
439→  return {
440→    project: state.project,
441→    isDirty: state.isDirty,
442→    lastSavedAt: state.lastSavedAt,
443→    canUndo: state.history.length > 0,
444→    canRedo: state.future.length > 0,
445→    dispatch,
446→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
447→  };
