 37→function screenToModel(screenX, screenY, viewport, svgRect) {
 38→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 39→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 40→  return { x, y };
 41→}
