 90→  const handleMouseDown = useCallback((e) => {
 91→    // Middle mouse or space+left for pan
 92→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 93→      isPanning.current = true;
 94→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 95→      e.preventDefault();
 96→      return;
 97→    }
 98→
 99→    const modelPos = getModelPos(e);
100→    if (pastePreview?.active && e.button === 0) {
101→      placePaste(modelPos);
102→      return;
103→    }
104→    tool.onMouseDown(modelPos, e);
105→  }, [getModelPos, pastePreview, placePaste, tool]);
106→
107→  const handleMouseMove = useCallback((e) => {
108→    if (isPanning.current) {
109→      const dx = e.clientX - lastPanPos.current.x;
110→      const dy = e.clientY - lastPanPos.current.y;
111→      editorDispatch({ type: 'PAN', dx, dy });
112→      lastPanPos.current = { x: e.clientX, y: e.clientY };
113→      return;
114→    }
