118→    setCursorPos(modelPos);
119→    if (pastePreview?.active) {
120→      updatePastePreview(modelPos);
121→      return;
122→    }
123→    tool.onMouseMove(modelPos, e);
124→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
125→
126→  const handleMouseUp = useCallback((e) => {
127→    if (isPanning.current) {
128→      isPanning.current = false;
129→      return;
130→    }
131→    if (pastePreview?.active) return;
132→    const modelPos = getModelPos(e);
