171→      if (isTypingTarget(e.target)) return;
172→
173→      if (e.key === ' ') {
174→        spaceHeld.current = true;
175→        e.preventDefault();
176→      }
177→
178→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
179→        const key = e.key.toLowerCase();
180→        if (key === 'c') {
