102→export function fitViewportToSheet(viewport, sheet) {
103→  const paper = getPaperPreset(sheet.paperSize);
104→  const width = clamp(viewport.width, 40, paper.width - SHEET_MARGIN * 2);
105→  const height = clamp(viewport.height, 30, paper.height - SHEET_MARGIN * 2 - TITLE_BLOCK_HEIGHT);
106→  const maxX = paper.width - SHEET_MARGIN - width;
107→  const maxY = paper.height - SHEET_MARGIN - height;
108→
109→  return {
110→    ...viewport,
111→    width,
112→    height,
113→    x: clamp(viewport.x, SHEET_MARGIN, maxX),
114→    y: clamp(viewport.y, SHEET_MARGIN, maxY),
115→  };
116→}
