 43→export default function SvgCanvas() {
 44→  const svgRef = useRef(null);
 45→  const isPanning = useRef(false);
 46→  const lastPanPos = useRef({ x: 0, y: 0 });
 47→  const spaceHeld = useRef(false);
 48→  const cursorPosRef = useRef({ x: 0, y: 0 });
 49→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 50→
 51→  const { dispatch, getFloor } = useProject();
 52→  const editor = useEditor();
 53→  const {
 54→    activeTool, selectedId, selectedType, toolState,
 55→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 56→    regionSelection, pastePreview,
 57→    dispatch: editorDispatch,
 58→  } = editor;
 59→
 60→  const floor = getFloor(activeFloorId);
 61→  const {
 62→    copySelection,
 63→    cutSelection,
 64→    beginPaste,
 65→    updatePastePreview,
 66→    cancelPaste,
 67→    placePaste,
 68→    previewContent,
 69→  } = usePlanClipboardController();
 70→
 71→  const tool = useEditorTool({
 72→    activeTool,
 73→    dispatch,
 74→    editorDispatch,
 75→    getFloor,
 76→    activeFloorId,
 77→    viewport,
 78→    snapEnabled,
 79→    selectedId,
 80→    selectedType,
 81→    toolState,
 82→    viewMode,
 83→  });
 84→
 85→  const getModelPos = useCallback((e) => {
 86→    const rect = svgRef.current.getBoundingClientRect();
 87→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 88→  }, [viewport]);
 89→
 90→  const handleMouseDown = useCallback((e) => {
 91→    // Middle mouse or space+left for pan
 92→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 93→      isPanning.current = true;
 94→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 95→      e.preventDefault();
 96→      return;
 97→    }
 98→
 99→    const modelPos = getModelPos(e);
100→    if (pastePreview?.active && e.button === 0) {
101→      placePaste(modelPos);
102→      return;
103→    }
104→    tool.onMouseDown(modelPos, e);
105→  }, [getModelPos, pastePreview, placePaste, tool]);
106→
107→  const handleMouseMove = useCallback((e) => {
108→    if (isPanning.current) {
109→      const dx = e.clientX - lastPanPos.current.x;
110→      const dy = e.clientY - lastPanPos.current.y;
111→      editorDispatch({ type: 'PAN', dx, dy });
112→      lastPanPos.current = { x: e.clientX, y: e.clientY };
113→      return;
114→    }
115→
116→    const modelPos = getModelPos(e);
117→    cursorPosRef.current = modelPos;
118→    setCursorPos(modelPos);
119→    if (pastePreview?.active) {
120→      updatePastePreview(modelPos);
121→      return;
122→    }
123→    tool.onMouseMove(modelPos, e);
124→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
125→
126→  const handleMouseUp = useCallback((e) => {
127→    if (isPanning.current) {
128→      isPanning.current = false;
129→      return;
130→    }
131→    if (pastePreview?.active) return;
132→    const modelPos = getModelPos(e);
133→    tool.onMouseUp(modelPos, e);
134→  }, [getModelPos, pastePreview, tool]);
135→
136→  const handleDoubleClick = useCallback((e) => {
137→    if (pastePreview?.active) return;
138→    const modelPos = getModelPos(e);
139→    tool.onDoubleClick(modelPos, e);
140→  }, [getModelPos, pastePreview, tool]);
141→
142→  const handleWheel = useCallback((e) => {
143→    e.preventDefault();
144→    const rect = svgRef.current.getBoundingClientRect();
145→    const mouseX = e.clientX - rect.left;
146→    const mouseY = e.clientY - rect.top;
147→
148→    const direction = e.deltaY < 0 ? 1 : -1;
149→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
150→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
151→
152→    // Zoom centered on cursor
153→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
154→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
155→
156→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
157→  }, [viewport, editorDispatch]);
158→
159→  useEffect(() => {
160→    if (!statusMessage) return undefined;
161→
162→    const timer = window.setTimeout(() => {
163→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
164→    }, 2500);
165→
166→    return () => window.clearTimeout(timer);
167→  }, [statusMessage, editorDispatch]);
168→
169→  useEffect(() => {
170→    const handleKeyDown = (e) => {
171→      if (isTypingTarget(e.target)) return;
172→
173→      if (e.key === ' ') {
174→        spaceHeld.current = true;
175→        e.preventDefault();
176→      }
177→
178→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
179→        const key = e.key.toLowerCase();
180→        if (key === 'c') {
181→          e.preventDefault();
182→          copySelection();
183→          return;
184→        }
185→        if (key === 'x') {
186→          e.preventDefault();
187→          cutSelection();
188→          return;
189→        }
190→        if (key === 'v') {
