208→            return;
209→          case 'm':
210→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
211→            return;
212→          case 'w':
213→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
214→            return;
215→          case 'b':
216→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
217→            return;
218→          case 't':
219→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
220→            return;
221→          case 'q':
222→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
223→            return;
224→          case 's':
225→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
226→            return;
227→          case 'r':
228→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
229→            return;
230→          case 'd':
231→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
232→            return;
233→          case 'n':
234→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
235→            return;
236→          case 'c':
237→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
238→            return;
239→        }
240→      }
241→
242→      tool.onKeyDown(e);
243→    };
244→
245→    const handleKeyUp = (e) => {
246→      if (isTypingTarget(e.target)) return;
247→
248→      if (e.key === ' ') {
249→        spaceHeld.current = false;
250→      }
251→    };
252→
253→    window.addEventListener('keydown', handleKeyDown);
254→    window.addEventListener('keyup', handleKeyUp);
255→    return () => {
256→      window.removeEventListener('keydown', handleKeyDown);
257→      window.removeEventListener('keyup', handleKeyUp);
258→    };
259→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
260→
261→  // Prevent default context menu on SVG
262→  useEffect(() => {
263→    const svg = svgRef.current;
264→    if (!svg) return;
265→    const prevent = (e) => e.preventDefault();
266→    svg.addEventListener('contextmenu', prevent);
267→    svg.addEventListener('wheel', handleWheel, { passive: false });
268→    return () => {
269→      svg.removeEventListener('contextmenu', prevent);
270→      svg.removeEventListener('wheel', handleWheel);
271→    };
272→  }, [handleWheel]);
273→
274→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
275→  const zoomPercent = Math.round(viewport.zoom * 1000);
276→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
277→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
278→    : null;
279→  const selectionCount = regionSelection?.objectCount || 0;
280→
281→  return (
282→    <div className={styles.canvasContainer}>
283→      <svg
284→        ref={svgRef}
285→        className={styles.svg}
286→        style={{ cursor }}
287→        onMouseDown={handleMouseDown}
288→        onMouseMove={handleMouseMove}
289→        onMouseUp={handleMouseUp}
290→        onDoubleClick={handleDoubleClick}
291→      >
292→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
293→          {viewMode === 'plan' && showGrid && <GridRenderer />}
294→          {viewMode === 'plan' && showGrid && (
295→            <rect
296→              x={-100000} y={-100000}
297→              width={200000} height={200000}
298→              fill="url(#grid-major)"
299→              style={{ pointerEvents: 'none' }}
