351→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
352→              </>
353→            ) : viewMode === 'section_view' ? (
354→              <SectionRenderer floor={floor} activeSectionCutId={activeSectionCutId} />
355→            ) : (
356→              <ElevationRenderer floor={floor} viewMode={viewMode} />
357→            )
358→          )}
359→        </g>
360→      </svg>
361→      <div className={styles.statusBar}>
362→        <span>X: {Math.round(cursorPos.x)} mm</span>
363→        <span>Y: {Math.round(cursorPos.y)} mm</span>
364→        <span>Zoom: {zoomPercent}%</span>
365→        <span>View: {viewMode}</span>
366→        <span>Tool: {activeTool}</span>
367→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
368→        {pastePreview?.active && <span>Paste: click to place</span>}
369→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
370→      </div>
371→    </div>
372→  );
373→}
