  1→import { getSheetDisplayLabel } from '@/domain/sheetModels';
  2→import { getPaperPreset } from './paper';
  3→import { getViewportSourceLabel, resolveSheetViewportSource } from './sources';
  4→
  5→const SHEET_MARGIN = 12;
  6→const TITLE_BLOCK_HEIGHT = 32;
  7→const CONTENT_PADDING = 4;
  8→
  9→function clamp(value, min, max) {
 10→  return Math.max(min, Math.min(max, value));
 11→}
 12→
 13→function resolveViewportScale(viewport) {
 14→  return Math.max(1, viewport.scale || 100);
 15→}
 16→
 17→function buildTitleBlock(project, sheet, paper) {
 18→  const titleBlockWidth = Math.min(130, paper.width * 0.42);
 19→  const x = paper.width - SHEET_MARGIN - titleBlockWidth;
 20→  const y = paper.height - SHEET_MARGIN - TITLE_BLOCK_HEIGHT;
 21→
 22→  return {
 23→    x,
 24→    y,
 25→    width: titleBlockWidth,
 26→    height: TITLE_BLOCK_HEIGHT,
 27→    rows: [
 28→      { label: 'Drawing', value: sheet.drawingName || getSheetDisplayLabel(sheet) },
 29→      { label: 'Project', value: sheet.projectNameOverride || project.name || 'Untitled Project' },
 30→      { label: 'Scale', value: sheet.scaleLabel || 'As noted' },
 31→    ],
 32→  };
 33→}
 34→
 35→function resolveViewportTitle(viewport, source) {
 36→  return viewport.title?.trim() || source.title || getViewportSourceLabel(viewport.sourceView);
 37→}
 38→
 39→function buildViewportFrame(viewport, source) {
 40→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 41→  const scale = 1 / resolveViewportScale(viewport);
 42→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 43→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 44→  const innerWidth = Math.max(10, viewport.width - CONTENT_PADDING * 2);
 45→  const innerHeight = Math.max(10, viewport.height - CONTENT_PADDING * 2);
 46→  const drawnWidth = sourceWidth * scale;
 47→  const drawnHeight = sourceHeight * scale;
 48→
 49→  const translateX = Math.max(0, (innerWidth - drawnWidth) / 2) - bounds.minX * scale;
 50→  const translateY = Math.max(0, (innerHeight - drawnHeight) / 2) - bounds.minY * scale;
 51→
 52→  return {
 53→    ...viewport,
 54→    rotation: viewport.rotation || 0,
 55→    title: resolveViewportTitle(viewport, source),
 56→    source,
 57→    clipRect: {
 58→      x: viewport.x + CONTENT_PADDING,
 59→      y: viewport.y + CONTENT_PADDING,
 60→      width: innerWidth,
 61→      height: innerHeight,
 62→    },
 63→    contentTransform: {
 64→      translateX,
 65→      translateY,
 66→      scale,
 67→    },
 68→  };
 69→}
 70→
 71→export function buildSheetScene(project, sheet) {
 72→  if (!sheet) return null;
 73→
 74→  const paper = getPaperPreset(sheet.paperSize);
 75→  const titleBlock = buildTitleBlock(project, sheet, paper);
 76→  const contentArea = {
 77→    x: SHEET_MARGIN,
 78→    y: SHEET_MARGIN,
 79→    width: paper.width - SHEET_MARGIN * 2,
 80→    height: paper.height - SHEET_MARGIN * 2,
 81→  };
 82→
 83→  const viewports = (sheet.viewports || []).map((viewport) => (
 84→    buildViewportFrame(viewport, resolveSheetViewportSource(project, viewport))
 85→  ));
 86→
 87→  return {
 88→    paper,
 89→    title: getSheetDisplayLabel(sheet),
 90→    border: {
 91→      x: SHEET_MARGIN,
 92→      y: SHEET_MARGIN,
 93→      width: paper.width - SHEET_MARGIN * 2,
 94→      height: paper.height - SHEET_MARGIN * 2,
 95→    },
 96→    contentArea,
 97→    titleBlock,
 98→    viewports,
 99→  };
100→}
101→
102→export function fitViewportToSheet(viewport, sheet) {
103→  const paper = getPaperPreset(sheet.paperSize);
104→  const width = clamp(viewport.width, 40, paper.width - SHEET_MARGIN * 2);
105→  const height = clamp(viewport.height, 30, paper.height - SHEET_MARGIN * 2 - TITLE_BLOCK_HEIGHT);
106→  const maxX = paper.width - SHEET_MARGIN - width;
107→  const maxY = paper.height - SHEET_MARGIN - height;
108→
109→  return {
110→    ...viewport,
111→    width,
112→    height,
113→    x: clamp(viewport.x, SHEET_MARGIN, maxX),
114→    y: clamp(viewport.y, SHEET_MARGIN, maxY),
115→  };
116→}
117→
118→export function getDefaultViewportRect(sheet, source, scale = 100) {
119→  const paper = getPaperPreset(sheet.paperSize);
120→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
121→  const denom = Math.max(1, scale);
122→  const width = Math.max(70, Math.min((bounds.maxX - bounds.minX) / denom + CONTENT_PADDING * 2, paper.width - SHEET_MARGIN * 2));
123→  const height = Math.max(50, Math.min((bounds.maxY - bounds.minY) / denom + CONTENT_PADDING * 2, paper.height - SHEET_MARGIN * 2 - TITLE_BLOCK_HEIGHT));
124→  return {
125→    x: SHEET_MARGIN + 8,
126→    y: SHEET_MARGIN + 8,
127→    width,
128→    height,
129→  };
130→}
