 55→export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
 56→  if (!selectedId || !floor) return null;
 57→
 58→  if (selectedType === 'slab') {
 59→    const slab = (floor.slabs || []).find(s => s.id === selectedId) || null;
 60→    const renderData = slab ? getSlabRenderData(slab) : null;
 61→    if (!renderData) return null;
 62→
 63→    const handleR = HANDLE_SIZE / zoom;
 64→    return (
 65→      <g>
 66→        <polygon
 67→          points={renderData.points}
 68→          fill="var(--color-selection-fill)"
 69→          stroke="var(--color-selection)"
 70→          strokeWidth={2}
 71→          strokeDasharray="6 3"
 72→          vectorEffect="non-scaling-stroke"
 73→        />
 74→        {renderData.outline.map((point, index) => (
 75→          <rect
 76→            key={`${point.x}-${point.y}-${index}`}
 77→            data-handle="slab-vertex"
 78→            data-index={index}
 79→            x={point.x - handleR / 2}
 80→            y={point.y - handleR / 2}
 81→            width={handleR}
 82→            height={handleR}
 83→            fill="white"
 84→            stroke="var(--color-selection)"
 85→            strokeWidth={2}
 86→            vectorEffect="non-scaling-stroke"
 87→            style={{ cursor: 'move' }}
 88→          />
 89→        ))}
 90→      </g>
 91→    );
 92→  }
 93→
 94→  if (selectedType === 'wall') {
 95→    const wall = floor.walls.find(w => w.id === selectedId);
 96→    if (!wall) return null;
 97→    return <WallSelection wall={wall} columns={floor.columns || []} zoom={zoom} />;
 98→  }
 99→
100→  if (selectedType === 'sectionCut') {
101→    const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId) || null;
102→    const renderData = getSectionCutRenderData(sectionCut);
103→    if (!renderData) return null;
104→    const handleR = HANDLE_SIZE / zoom;
105→
106→    return (
107→      <g>
108→        <line
109→          x1={renderData.line.start.x}
110→          y1={renderData.line.start.y}
111→          x2={renderData.line.end.x}
112→          y2={renderData.line.end.y}
113→          stroke="var(--color-selection)"
114→          strokeWidth={2}
115→          strokeDasharray="6 3"
116→          vectorEffect="non-scaling-stroke"
117→        />
118→        <rect
119→          data-handle="start"
120→          x={sectionCut.startPoint.x - handleR / 2}
121→          y={sectionCut.startPoint.y - handleR / 2}
122→          width={handleR}
123→          height={handleR}
124→          fill="white"
125→          stroke="var(--color-selection)"
126→          strokeWidth={2}
127→          vectorEffect="non-scaling-stroke"
128→          style={{ cursor: 'move' }}
129→        />
130→        <rect
131→          data-handle="end"
132→          x={sectionCut.endPoint.x - handleR / 2}
133→          y={sectionCut.endPoint.y - handleR / 2}
134→          width={handleR}
135→          height={handleR}
136→          fill="white"
137→          stroke="var(--color-selection)"
138→          strokeWidth={2}
139→          vectorEffect="non-scaling-stroke"
140→          style={{ cursor: 'move' }}
141→        />
142→      </g>
143→    );
144→  }
145→
146→  if (selectedType === 'annotation') {
147→    const figure = getManualAnnotationFigure(floor, selectedId);
148→    if (!figure) return null;
149→    return (
150→      <g>
151→        {figure.extensionLines.map((line, index) => (
152→          <line
153→            key={`annotation-ext-${index}`}
154→            x1={line.start.x}
155→            y1={line.start.y}
156→            x2={line.end.x}
157→            y2={line.end.y}
158→            stroke="var(--color-selection)"
159→            strokeWidth={2}
160→            strokeDasharray="6 3"
161→            vectorEffect="non-scaling-stroke"
162→          />
163→        ))}
164→        <line
165→          x1={figure.lineStart.x}
166→          y1={figure.lineStart.y}
167→          x2={figure.lineEnd.x}
168→          y2={figure.lineEnd.y}
169→          stroke="var(--color-selection)"
170→          strokeWidth={2}
171→          strokeDasharray="6 3"
172→          vectorEffect="non-scaling-stroke"
173→        />
174→      </g>
175→    );
176→  }
177→
178→  if (selectedType === 'door') {
179→    const door = floor.doors.find(d => d.id === selectedId);
180→    if (!door) return null;
181→    const wall = floor.walls.find(w => w.id === door.wallId);
182→    if (!wall) return null;
183→    // Highlight parent wall subtly
184→    const outline = getWallRenderData(wall, floor.columns || []).outline;
185→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
186→    return (
187→      <polygon
188→        points={points}
189→        fill="none"
190→        stroke="var(--color-selection)"
191→        strokeWidth={2}
192→        strokeDasharray="6 3"
193→        vectorEffect="non-scaling-stroke"
194→      />
195→    );
196→  }
197→
198→  if (selectedType === 'beam') {
199→    const beam = (floor.beams || []).find(b => b.id === selectedId);
200→    if (!beam) return null;
201→    const renderData = getBeamRenderData(beam, floor.columns || []);
202→    if (!renderData) return null;
203→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
204→    return (
205→      <polygon
206→        points={points}
207→        fill="var(--color-selection-fill)"
208→        stroke="var(--color-selection)"
209→        strokeWidth={2}
210→        strokeDasharray="6 3"
211→        vectorEffect="non-scaling-stroke"
212→      />
213→    );
214→  }
215→
216→  if (selectedType === 'stair') {
217→    const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
218→    if (!stair) return null;
219→    const renderData = getStairRenderData(stair);
220→    if (!renderData) return null;
221→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
222→    return (
223→      <polygon
224→        points={points}
225→        fill="var(--color-selection-fill)"
226→        stroke="var(--color-selection)"
227→        strokeWidth={2}
228→        strokeDasharray="6 3"
229→        vectorEffect="non-scaling-stroke"
230→      />
231→    );
232→  }
233→
234→  if (selectedType === 'window') {
235→    const win = floor.windows.find(w => w.id === selectedId);
236→    if (!win) return null;
237→    const wall = floor.walls.find(w => w.id === win.wallId);
238→    if (!wall) return null;
239→    const outline = getWallRenderData(wall, floor.columns || []).outline;
240→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
241→    return (
242→      <polygon
243→        points={points}
244→        fill="none"
245→        stroke="var(--color-selection)"
246→        strokeWidth={2}
247→        strokeDasharray="6 3"
248→        vectorEffect="non-scaling-stroke"
249→      />
250→    );
251→  }
252→
253→  if (selectedType === 'column') {
254→    const column = (floor.columns || []).find(c => c.id === selectedId);
255→    if (!column) return null;
256→    const outline = columnOutline(column);
257→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
258→    const handleR = HANDLE_SIZE / zoom;
259→    return (
260→      <g>
261→        <polygon
262→          points={points}
263→          fill="var(--color-selection-fill)"
264→          stroke="var(--color-selection)"
265→          strokeWidth={2}
266→          strokeDasharray="6 3"
267→          vectorEffect="non-scaling-stroke"
268→        />
269→        {outline.map((p, i) => (
270→          <rect
271→            key={i}
272→            x={p.x - handleR / 2}
273→            y={p.y - handleR / 2}
274→            width={handleR}
275→            height={handleR}
276→            fill="white"
277→            stroke="var(--color-selection)"
278→            strokeWidth={2}
279→            vectorEffect="non-scaling-stroke"
280→            style={{ cursor: 'move' }}
281→          />
282→        ))}
283→      </g>
284→    );
285→  }
286→
287→  if (selectedType === 'room') {
288→    const room = floor.rooms.find(r => r.id === selectedId);
289→    if (!room?.points?.length) return null;
290→    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
291→    return (
292→      <polygon
293→        points={points}
294→        fill="none"
295→        stroke="var(--color-selection)"
296→        strokeWidth={2}
297→        strokeDasharray="6 3"
298→        vectorEffect="non-scaling-stroke"
299→      />
300→    );
301→  }
302→
303→  return null;
304→}
